### 1. Basic Increment Operations
```typescript
describe("incrementReplayCount - basic operations", () => {
  it("should increment replayCount from 0 to 1 for new entry", async () => {
    const entry = await createHistoryEntry({ input: {} });
    await incrementReplayCount(entry.id);
    const result = await getHistoryEntry(entry.id);
    expect(result.input.replayCount).toBe(1);

    // LOGGING: Verify increment was logged
    expect(mockLogger.debug).toHaveBeenCalledWith(
      expect.objectContaining({
        event: "replay_count_incremented",
        entryId: entry.id,
        oldCount: 0,
        newCount: 1,
      })
    );
  });

  it("should increment existing replayCount from 5 to 6", async () => {
    const entry = await createHistoryEntry({ input: { replayCount: 5 } });
    await incrementReplayCount(entry.id);
    const result = await getHistoryEntry(entry.id);
    expect(result.input.replayCount).toBe(6);
  });

  it("should return the new count after increment", async () => {
    const entry = await createHistoryEntry({ input: { replayCount: 10 } });
    const newCount = await incrementReplayCount(entry.id);
    expect(newCount).toBe(11);
  });
});
```

### 2. Null/Missing Input Handling
```typescript
describe("incrementReplayCount - null handling", () => {
  it("should handle null input column gracefully", async () => {
    await db.run(sql`INSERT INTO history (id, input) VALUES ("null-test", NULL)`);
    await incrementReplayCount("null-test");
    const result = await getHistoryEntry("null-test");
    expect(result.input.replayCount).toBe(1);
  });

  it("should handle missing replayCount key", async () => {
    const entry = await createHistoryEntry({ input: { otherField: "value" } });
    await incrementReplayCount(entry.id);
    const result = await getHistoryEntry(entry.id);
    expect(result.input.replayCount).toBe(1);
    expect(result.input.otherField).toBe("value"); // Preserve other fields
  });

  it("should handle empty object input", async () => {
    const entry = await createHistoryEntry({ input: {} });
    await incrementReplayCount(entry.id);
    expect((await getHistoryEntry(entry.id)).input.replayCount).toBe(1);
  });
});
```

### 3. Concurrent Increment Tests (CRITICAL FOR RACE CONDITION FIX)
```typescript
describe("incrementReplayCount - concurrency", () => {
  it("should correctly count 100 concurrent increments", async () => {
    const entry = await createHistoryEntry({ input: { replayCount: 0 } });
    const startTime = Date.now();

    // Fire 100 concurrent increments
    const promises = Array.from({ length: 100 }, () => 
      incrementReplayCount(entry.id)
    );
    await Promise.all(promises);

    const result = await getHistoryEntry(entry.id);
    const elapsed = Date.now() - startTime;

    // CRITICAL ASSERTION: Must be exactly 100
    expect(result.input.replayCount).toBe(100);

    // LOGGING: Performance check
    console.log(`[PERF] 100 concurrent increments completed in ${elapsed}ms`);
    expect(elapsed).toBeLessThan(5000); // Should complete within 5s
  });

  it("should handle concurrent increments with random delays", async () => {
    const entry = await createHistoryEntry({ input: { replayCount: 0 } });

    const promises = Array.from({ length: 50 }, async (_, i) => {
      await new Promise(r => setTimeout(r, Math.random() * 10));
      return incrementReplayCount(entry.id);
    });
    await Promise.all(promises);

    expect((await getHistoryEntry(entry.id)).input.replayCount).toBe(50);
  });

  it("should handle burst of 1000 increments without data loss", async () => {
    const entry = await createHistoryEntry({ input: { replayCount: 0 } });

    // Higher load test
    const promises = Array.from({ length: 1000 }, () => 
      incrementReplayCount(entry.id)
    );
    await Promise.all(promises);

    expect((await getHistoryEntry(entry.id)).input.replayCount).toBe(1000);
  });
});
```

