### 5. SQL Atomicity Verification
```typescript
describe("incrementReplayCount - SQL verification", () => {
  it("should use atomic SQL (single UPDATE, no SELECT)", async () => {
    const spy = jest.spyOn(db, "run");
    const entry = await createHistoryEntry({ input: { replayCount: 5 } });

    await incrementReplayCount(entry.id);

    // Should NOT have SELECT for read-modify-write
    const selectCalls = spy.mock.calls.filter(
      call => call[0]?.sql?.toUpperCase().includes("SELECT")
    );
    expect(selectCalls.filter(c => c[0]?.sql?.includes("replayCount"))).toHaveLength(0);

    // Should have atomic UPDATE with json_set
    const updateCalls = spy.mock.calls.filter(
      call => call[0]?.sql?.toUpperCase().includes("UPDATE")
    );
    expect(updateCalls.some(c => 
      c[0]?.sql?.includes("json_set") && c[0]?.sql?.includes("+ 1")
    )).toBe(true);
  });
});
```

